var e=[{id:`L2_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`일제 사격! 머리의 파손부를 노려라!`,JPN:`一斉射撃！　頭の破損部を狙え！`,ENG:`All hands, FIRE! Aim for the damaged area on the head!`,TWN:`全體射擊！瞄準頭部毀損處！`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:null,C:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_SERIOUS`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`GUARD_BORDER_NULL_NULL`,text:{KOREA:`놈이 장벽을 들이받으려 합니다!`,JPN:`やつが障壁を突き破ろうとしています！`,ENG:`The monster's trying to break through the wall!`,TWN:`這傢伙想撞破城牆！`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`충격 대비! 완충 배리어 전개!`,JPN:`衝撃に備えろ！　緩衝バリアを展開！`,ENG:`Brace for impact! Activate the shock absorption barrier!`,TWN:`預防衝擊！展開緩衝護盾！`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_SERIOUS`}}}},{id:`L16_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`다들 괜찮나?`,JPN:`みんな大丈夫か？`,ENG:`Is everyone all right?`,TWN:`大家還好嗎？`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:null,C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`GUARD_BORDER_NULL_NULL`,text:{KOREA:`콜록, 콜록… 괜찮습니다.`,JPN:`ゲホ、ゲホ……大丈夫です。`,ENG:`*Cough...!* *Cough!* We're good, sir.`,TWN:`咳咳，咳咳…… 還好。`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`GUARD_BORDER_NULL_NULL`,text:{KOREA:`2종 침식체, 무력화 확인!`,JPN:`第2種侵食体、無力化を確認！`,ENG:`Category 2 C.O., neutralized!`,TWN:`2類侵蝕體，確認失去攻擊力！`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`장벽의 상태는?`,JPN:`障壁の状態は？`,ENG:`What about the wall?`,TWN:`城牆的狀態呢？`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`GUARD_BORDER_NULL_NULL`,text:{KOREA:`일부 손상됐지만 다행히 관통된 곳은 없습니다.`,JPN:`一部損傷を受けてますが、幸い貫通したところはありません。`,ENG:`It's damaged, but still intact, sir!`,TWN:`雖然有部分毀損，但所幸沒有破洞。`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:{char_id:`GUARD_BORDER_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`}}}},{id:`L22_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`큭… 크큭…`,JPN:`クッ……ククッ……`,ENG:`Hah... Hah hah...!`,TWN:`咳… 咳咳…`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:null,C:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_PRIDE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`모두 잘해 줬다! 우리가 2종 놈을 막았어!`,JPN:`みんな、よくやってくれた！　俺たちが第2種の野郎を食い止めたんだ！`,ENG:`Well done! We stopped a Category 2 C.O.!`,TWN:`大家都做得很好！我們成功擋下2類！`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:null,C:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`CURIAN_BORDER_NULL_FAKE`,text:{KOREA:`다행이군. 우리가 도착하기 전에 해결된 모양이야.`,JPN:`よかったな。私たちが到着する前に解決したようだ。`,ENG:`Thank god. They managed to defeat it before we arrived.`,TWN:`真是萬幸，似乎在我們抵達前就已經處理完畢。`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:null,C:{char_id:`CURIAN_BORDER_NULL_FAKE`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`ELLA_BORDER_NULL_NULL`,text:{KOREA:`아니. 워치에 반응이 와. 침식파가 아직 사라지지 않았어.`,JPN:`いや。ウォッチに反応がある。まだ侵食波が消えていない。`,ENG:`No. My Watch is still reacting. The Corruption ray hasn't disappeared yet.`,TWN:`不對，能量環有反應，侵蝕波還沒有消失。`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:null,C:{char_id:`ELLA_BORDER_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`각자 파편 회수하고, 장벽 보수 작업 준비해.`,JPN:`各自、破片を回収して障壁を補修する準備をしろ。`,ENG:`Collect the rubble and get ready to repair the wall.`,TWN:`大家回收碎片，準備維修城牆。`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:null,C:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`WATT_BORDER_NULL_ARMED`,text:{KOREA:`오늘 저녁은 든든하게 먹자고.`,JPN:`今日の夕飯はいっぱい食べようぜ。`,ENG:`But tonight, we feast!`,TWN:`今晚要吃飽點！`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:null,C:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`GUARD_BORDER_NULL_WATCHER`,text:{KOREA:`<color=#ffd34c>어라? 2종 침식체 신호가 다시 잡히고 있습니다.</color>`,JPN:`<color=#ffd34c>おや？　第2種侵食体の信号がまた現れました。</color>`,ENG:`<color=#ffd34c>Huh? The Category 2 C.O.'s signal is picking up again.</color>`,TWN:`<color=#ffd34c>嗯？又收到2類侵蝕體的訊號。</color>`},stage:{bg:`NOMAD_VILLAGE`,slots:{L:null,C:{char_id:`WATT_BORDER_NULL_ARMED`,face:`UNIT_IDLE`},R:null}}}];export{e as default};